<?php
namespace App\Services\Billing;
use App\Models\{Hotel,Plan};use Illuminate\Support\Facades\Http;use RuntimeException;
class StripeBilling{private function request(string$path,array$data):array{$secret=config('services.stripe.secret');if(blank($secret))throw new RuntimeException('Stripe is not configured.');$response=Http::asForm()->withBasicAuth($secret,'')->post("https://api.stripe.com/v1/{$path}",$data);if($response->failed())throw new RuntimeException($response->json('error.message')??'Stripe request failed.');return$response->json();}
public function checkout(Hotel$hotel,Plan$plan,string$email):string{$price=$plan->stripe_price_id?:env('STRIPE_PRICE_'.strtoupper($plan->key));if(blank($price))throw new RuntimeException("Stripe price is not configured for {$plan->name}.");$subscription=$hotel->subscription;$data=['mode'=>'subscription','line_items'=>[['price'=>$price,'quantity'=>1]],'success_url'=>route('platform.billing.index').'?checkout=success','cancel_url'=>route('platform.billing.index').'?checkout=cancelled','client_reference_id'=>(string)$hotel->id,'metadata'=>['hotel_id'=>(string)$hotel->id,'plan_id'=>(string)$plan->id],'subscription_data'=>['metadata'=>['hotel_id'=>(string)$hotel->id,'plan_id'=>(string)$plan->id]],'allow_promotion_codes'=>'true'];if($subscription?->provider_customer_id)$data['customer']=$subscription->provider_customer_id;else$data['customer_email']=$email;return$this->request('checkout/sessions',$data)['url']??throw new RuntimeException('Stripe did not return a Checkout URL.');}
public function portal(Hotel$hotel):string{$customer=$hotel->subscription?->provider_customer_id;if(blank($customer))throw new RuntimeException('This hotel does not have a Stripe customer yet.');return$this->request('billing_portal/sessions',['customer'=>$customer,'return_url'=>route('platform.billing.index')])['url']??throw new RuntimeException('Stripe did not return a portal URL.');}}
